    56→		const stack = new Error('CREATED via:').stack!;
    57→		this._registry.register(disposable, stack, disposable);
    58→	}
    59→
    60→	setParent(child: IDisposable, parent: IDisposable | null): void {
    61→		if (parent) {
    62→			this._registry.unregister(child);
    63→		} else {
