    65→		}
    66→	}
    67→
    68→	markAsDisposed(disposable: IDisposable): void {
    69→		this._registry.unregister(disposable);
    70→	}
    71→
    72→	markAsSingleton(disposable: IDisposable): void {
    73→		this._registry.unregister(disposable);
